		total := state.total

		// Check if we've reached the destination
		if row == m-1 && col == n-1 {
			return total
		}

		// Check if we've already visited this cell with a lower or equal cost
		if existing, exists := visited[row][col][time]; exists && existing <= total {
			continue
		}
